    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'ميكانيكا', 'اختيار من متعدد', 'ذهب محمد من الغرب إلى الشرق 20m وعاد للشرق 15m احسب المسافة والإزاحة:', '["المسافة 35 m والإزاحة 5 m", "المسافة 5 m والإزاحة 35 m", "المسافة 35 m والإزاحة 35 m", "المسافة 35 m والإزاحة 0 m"]'::jsonb, 0, 'المسافة المقطوعة = 20+15 = 35 m. الإزاحة = الفرق بين النهاية والبداية = 20-15 = 5 m.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'ميكانيكا', 'اختيار من متعدد', 'حسب قانون كولوم فإن القوة الكهربائية F تتناسب مع المسافة بين الشحنتين r حسب العلاقة:', '["F ∝ 1/r²", "F ∝ 1/r", "F ∝ r²", "F ∝ r"]'::jsonb, 0, 'قانون كولوم: F = k(q₁q₂)/r²، أي تتناسب عكسياً مع مربع المسافة.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'عام', 'اختيار من متعدد', 'أي التالي يصف قوتا زوجا التأثير المتبادل؟', '["متفقان في المقدار والاتجاه", "متفقان في المقدار مختلفان في الاتجاه", "مختلفان في المقدار متفقان في الاتجاه", "مختلفان في المقدار والاتجاه"]'::jsonb, 1, 'حسب قانون نيوتن الثالث: لكل فعل ردة فعل مساوية في المقدار ومعاكسة في الاتجاه.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'عام', 'اختيار من متعدد', 'ما الذي يؤثر في مرونة المادة الصلبة؟', '["القوة المرنة", "القوة الميكانيكية", "القوة الكهربائية", "القوة الكهرومغناطيسية"]'::jsonb, 3, 'القوة الكهرومغناطيسية بين الذرات هي المسؤولة عن مرونة المواد الصلبة.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'موجات', 'اختيار من متعدد', 'وفق نظرية أينشتاين، الضوء ينحرف عند مروره بجانب:', '["كتلة كبيرة جداً", "كتلة صغيرة جداً", "حقل كهربائي", "حقل مغناطيسي"]'::jsonb, 0, 'النسبية العامة لأينشتاين تنص على أن الكتل الكبيرة (مثل النجوم والثقوب السوداء) تحني الزمكان وتحرف الضوء.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'ميكانيكا', 'اختيار من متعدد', 'إذا تم شد جسم لأعلى وكانت قوة الوزن mg فإن القوة العمودية هي:', '["مساوية لها", "أكبر منها", "أصغر منها", "ضعفها"]'::jsonb, 2, 'عند الشد لأعلى، القوة العمودية على الجسم تقل لأن جزءاً من الوزن يحمله الشد.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'موجات', 'اختيار من متعدد', 'صدى الصوت هو ظاهرة فيزيائية ناتجة عن:', '["الحيود", "التداخل", "الانعكاس", "الانكسار"]'::jsonb, 2, 'الصدى ناتج عن انعكاس الموجات الصوتية عن سطح بعيد ورجوعها للأذن.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'ميكانيكا', 'اختيار من متعدد', 'يتحرك سلك مستقيم بسرعة 2 m/s عمودياً على مجال مغناطيسي منتظم شدته 0.2 T، فتولدت فيه قوة دافعة حثية مقدارها 0.2 V، طول السلك يساوي:', '["0.1", "0.3", "0.5", "0.7"]'::jsonb, 2, 'EMF = BLv ⟹ 0.2 = 0.2 × L × 2 ⟹ L = 0.5 m.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'ميكانيكا', 'اختيار من متعدد', 'إذا كان عزم دوران باب 150 N·m وطوله 50 cm، أوجد القوة بوحدات الدولية.', '["150", "300", "600", "750"]'::jsonb, 1, 'τ = F × r ⟹ 150 = F × 0.5 ⟹ F = 300 N.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'ميكانيكا', 'اختيار من متعدد', 'احسب القدرة إذا دفع صندوق كتلته 5 kg لمسافة 50 m لمدة s 5 ثوانٍ (g = 10 m/s²):', '["1000 W", "500 W", "250 W", "125 W"]'::jsonb, 1, 'الشغل = mgd = 5×10×50 = 2500 J. القدرة = الشغل/الزمن = 2500/5 = 500 W.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'فيزياء', 'ميكانيكا', 'اختيار من متعدد', 'طبقاً لنظرية (الشغل-الطاقة) W = ΔKE فإذا بذل المحيط الخارجي شغلاً على نظام مكون من صندوق متحرك أفقياً على سطح أملس فإن الطاقة الحركية للصندوق:', '["تقل", "ثبت", "تذبذب", "تزيد"]'::jsonb, 3, 'إذا كان الشغل المبذول موجب، تزداد الطاقة الحركية.', grp_id, NULL, false, 'active', false);
