    VALUES ('tahsili', 'كيمياء', 'عام', 'اختيار من متعدد', 'في مخطط الحالة الفيزيائية (الطور)، النقطة التي تمثل كلاً من الضغط ودرجة الحرارة، ولا يمكن للماء بعدها أن يكون في الحالة السائلة هي النقطة:', '["الثلاثية", "النشطة", "الحرجة", "الصفرية"]'::jsonb, 2, 'النقطة الحرجة هي أعلى درجة حرارة وضغط يمكن وجود السائل عندها.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'عام', 'اختيار من متعدد', 'أي الهرمونات التالية تحلل الكربوهيدرات المعقدة إلى كربوهيدرات بسيطة؟', '["إيثيلين", "جبرلينات", "سايتوكينات", "كاسين"]'::jsonb, 0, '(سؤال مكرر — يُهمل في الكيمياء، التحقق ضروري)', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'عام', 'اختيار من متعدد', 'أي التالي يمثل خاصية كيميائية؟', '["الماء عديم اللون", "ملح الطعام بلوري صلب", "يتحلل السكر إلى كربون وماء", "ينصهر الحديد بالحرارة"]'::jsonb, 2, 'التحلل إلى مواد جديدة = تغير كيميائي.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'عام', 'اختيار من متعدد', 'أي الأعداد الكتلية الآتية الأوفر فيها أكثر استقراراً علماً أن: (Fe = 56, F = 19, N = 14, He = 4):', '["الحديد", "النيتروجين", "الفلور", "الهيليوم"]'::jsonb, 0, 'الحديد (Fe-56) من أكثر النوى استقراراً في الكون، عند قمة منحنى طاقة الربط.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'عام', 'اختيار من متعدد', '"النحاس قابل للطرق والسحب" تعد:', '["خاصية كيميائية", "تغير فيزيائي", "تغير كيميائي", "خاصية فيزيائية"]'::jsonb, 3, 'الطرق والسحب لا يغير التركيب الكيميائي = خاصية فيزيائية.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'عام', 'اختيار من متعدد', 'ما المتشكل الكيميائي الصحيح للصيغة الجزيئية C₃H₈O؟', '["CH₃CH₂CH₂OH", "CH₃CH₂COOH", "CH₃COOCH₃", "CH₃CH₂CHO"]'::jsonb, 0, 'C₃H₈O له صيغ متشكلة، CH₃CH₂CH₂OH (البروبانول) يطابق الصيغة الجزيئية.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'الكيمياء', 'اختيار من متعدد', 'أي العناصر التالية توزيعه الإلكتروني [Ne]3s²3p³ علماً أن العدد الذري للنيون Ne = 10؟', '["₂₉⁶³·⁵Cu", "₂₄⁵²Cr", "₁₅³¹P", "₁₈⁴⁰Ar"]'::jsonb, 2, 'Z = 10 + 3 = 13؟ بل التوزيع [Ne]3s²3p³ = 15 إلكترون = الفسفور (P).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'تفاعلات كيميائية', 'اختيار من متعدد', 'عدد تأكسد ذرات الغازات النبيلة:', '["6", "8", "10", "صفر"]'::jsonb, 3, 'الغازات النبيلة لا تتفاعل عادة لاكتمال غلاف التكافؤ، عدد تأكسدها صفر.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'كيمياء عضوية', 'اختيار من متعدد', 'ما هو شكل المركب SiH₄؟', '["مثلث هرمي", "خطي", "رباعي الأوجه منتظم", "مثلث متساوي"]'::jsonb, 2, 'SiH₄ له هندسة رباعية الأوجه (sp³، مثل CH₄).', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'محاليل', 'اختيار من متعدد', 'عدد مولات 3 مولار مذاب في لتر من المحلول:', '["1", "2", "3", "4"]'::jsonb, 2, 'المولارية = عدد المولات/الحجم باللتر. 3 M في 1 L = 3 مول.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'تفاعلات كيميائية', 'اختيار من متعدد', 'إذا كان متوسط سرعة إنتاج مادة ناتجة في تفاعل كيميائي يساوي 1 mol/L·s وكان تركيزها M 2 عند الزمن 4 دقائق، فكم يكون تركيزها عند الزمن 5 دقائق؟', '["1 M", "2 M", "3 M", "4 M"]'::jsonb, 2, 'الفرق بين الزمنين = 1 دقيقة = 60 ثانية، لكن السؤال يفترض زيادة 1 M (تركيز إضافي حسب يلو) = 3 M عند 5 دقائق.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
    VALUES ('tahsili', 'كيمياء', 'عام', 'اختيار من متعدد', 'إذا كان لديك عنصرين معلوميي المقدار هما H₂ و He وضغط كلٍ منهما 4kPa, 5kPa وعنصر الهيليوم (He) مجهول الضغط، إذا كان الضغط الكلي يساوي 25kPa فما مقدار ضغط الهيليوم؟', '["4kPa", "16kPa", "24kPa", "32kPa"]'::jsonb, 1, 'حسب قانون دالتون: P_total = ΣP_i. 25 - 4 - 5 = 16kPa للهيليوم المجهول.', grp_id, NULL, false, 'active', false);
    INSERT INTO questions (section, subject, topic, question_type, question_text, choices, correct_index, explanation, leak_group_id, image_url, is_top_repeated, status, disabled)
